# tests/integration/test_api_users.py import pytest from rest_framework import status
@pytest.mark.django_db class TestUserListAPI: """Tests for GET /api/v1/users/."""
endpoint = "/api/v1/users/"
def test_requires_authentication(self, api_client): """Returns 401 for unauthenticated requests.""" response = api_client.get(self.endpoint) assert response.status_code == status.HTTP_401_UNAUTHORIZED
def test_returns_user_list(self, authenticated_client, user_factory): """Returns paginated list of users.""" user_factory.create_batch(3)
response = authenticated_client.get(self.endpoint)
assert response.status_code == status.HTTP_200_OK assert "results" in response.data assert len(response.data["results"]) >= 3
def test_filters_by_user_type(self, authenticated_client, user_factory, admin_user_factory): """Filters users by user_type query param.""" user_factory.create_batch(2, user_type="regular") admin_user_factory.create_batch(2)
response = authenticated_client.get(f"{self.endpoint}?user_type=admin")
assert response.status_code == status.HTTP_200_OK assert all(u["user_type"] == "admin" for u in response.data["results"])
@pytest.mark.django_db class TestUserCreateAPI: """Tests for POST /api/v1/users/."""
endpoint = "/api/v1/users/"
def test_admin_can_create_user(self, admin_client): """Admin can create new users.""" payload = { "email": "newuser@example.com", "name": "New User", "user_type": "regular" }
response = admin_client.post(self.endpoint, payload, format="json")
assert response.status_code == status.HTTP_201_CREATED assert response.data["email"] == payload["email"]
def test_regular_user_cannot_create(self, authenticated_client): """Regular users get 403 Forbidden.""" payload = {"email": "test@example.com", "name": "Test"}
response = authenticated_client.post(self.endpoint, payload, format="json")
assert response.status_code == status.HTTP_403_FORBIDDEN
@pytest.mark.parametrize("field,value,error", [ ("email", "invalid", "Enter a valid email address"), ("email", "", "This field may not be blank"), ("name", "", "This field may not be blank"), ]) def test_validation_errors(self, admin_client, field, value, error): """Returns validation errors for invalid data.""" payload = {"email": "test@example.com", "name": "Test"} payload[field] = value
response = admin_client.post(self.endpoint, payload, format="json")
assert response.status_code == status.HTTP_400_BAD_REQUEST assert error in str(response.data[field])
@pytest.mark.django_db class TestUserDetailAPI: """Tests for GET/PATCH/DELETE /api/v1/users/{uid}/."""
def test_get_user_by_uid(self, authenticated_client, user): """Retrieves user by UID.""" response = authenticated_client.get(f"/api/v1/users/{user.uid}/")
assert response.status_code == status.HTTP_200_OK assert response.data["uid"] == str(user.uid) assert response.data["email"] == user.email
def test_update_own_profile(self, authenticated_client, user): """User can update their own profile.""" response = authenticated_client.patch( f"/api/v1/users/{user.uid}/", {"name": "Updated Name"}, format="json" )
assert response.status_code == status.HTTP_200_OK assert response.data["name"] == "Updated Name"
def test_cannot_update_others(self, authenticated_client, user_factory): """Cannot update other user's profile.""" other_user = user_factory()
response = authenticated_client.patch( f"/api/v1/users/{other_user.uid}/", {"name": "Hacked"}, format="json" )
assert response.status_code == status.HTTP_403_FORBIDDEN

# tests/unit/test_services.py import pytest from decimal import Decimal from unittest.mock import patch, MagicMock from apps.orders.services import OrderService from apps.orders.exceptions import InsufficientStockError
@pytest.mark.django_db class TestOrderService: """Tests for OrderService.create_order()."""
def test_creates_order_with_valid_items(self, user, product_factory): """Order is created with correct user and items.""" product = product_factory(price=Decimal("50.00"), stock=10)
order = OrderService.create_order( user=user, items=[{"product_id": product.id, "quantity": 2}] )
assert order.user == user assert order.status == "pending" assert order.items.count() == 1
def test_calculates_total_correctly(self, user, product_factory): """Order total equals sum of item prices.""" product = product_factory(price=Decimal("25.00"))
order = OrderService.create_order( user=user, items=[{"product_id": product.id, "quantity": 4}] )
assert order.total == Decimal("100.00")
def test_reduces_product_stock(self, user, product_factory): """Stock is reduced after order creation.""" product = product_factory(stock=10)
OrderService.create_order( user=user, items=[{"product_id": product.id, "quantity": 3}] )
product.refresh_from_db() assert product.stock == 7
def test_raises_error_for_insufficient_stock(self, user, product_factory): """InsufficientStockError for oversized orders.""" product = product_factory(stock=5)
with pytest.raises(InsufficientStockError) as exc_info: OrderService.create_order( user=user, items=[{"product_id": product.id, "quantity": 10}] )
assert exc_info.value.product_id == product.id assert exc_info.value.available == 5
@patch("apps.orders.services.send_order_confirmation") def test_sends_confirmation_email(self, mock_send, user, product_factory): """Confirmation email task is triggered.""" product = product_factory()
order = OrderService.create_order( user=user, items=[{"product_id": product.id, "quantity": 1}] )
mock_send.delay.assert_called_once_with(order_id=order.id)

# tests/integration/test_permissions.py import pytest from rest_framework import status
@pytest.mark.django_db class TestOrderPermissions: """Permission tests for Order API."""
def test_anonymous_cannot_list_orders(self, api_client): """Anonymous users get 401.""" response = api_client.get("/api/v1/orders/") assert response.status_code == status.HTTP_401_UNAUTHORIZED
def test_user_sees_only_own_orders(self, authenticated_client, user, order_factory, user_factory): """Users only see their own orders.""" # User's orders order_factory.create_batch(2, user=user) # Other user's orders other = user_factory() order_factory.create_batch(3, user=other)
response = authenticated_client.get("/api/v1/orders/")
assert response.status_code == status.HTTP_200_OK assert len(response.data["results"]) == 2
def test_admin_sees_all_orders(self, admin_client, order_factory): """Admins see all orders.""" order_factory.create_batch(5)
response = admin_client.get("/api/v1/orders/")
assert response.status_code == status.HTTP_200_OK assert len(response.data["results"]) == 5
def test_cannot_access_other_users_order(self, authenticated_client, order_factory, user_factory): """403 when accessing another user's order.""" other_user = user_factory() order = order_factory(user=other_user)
response = authenticated_client.get(f"/api/v1/orders/{order.uid}/")
assert response.status_code == status.HTTP_403_FORBIDDEN

# tests/unit/test_tasks.py import pytest from unittest.mock import patch from apps.orders.tasks import send_order_confirmation
@pytest.mark.django_db class TestOrderTasks: """Tests for Celery tasks."""
@patch("apps.orders.tasks.send_mail") def test_sends_confirmation_email(self, mock_send_mail, order): """send_order_confirmation sends email.""" send_order_confirmation(order_id=order.id)
mock_send_mail.assert_called_once() call_kwargs = mock_send_mail.call_args.kwargs assert order.user.email in call_kwargs["recipient_list"] assert order.order_number in call_kwargs["subject"]
def test_handles_missing_order(self): """Task handles non-existent order gracefully.""" # Should not raise, just log warning result = send_order_confirmation(order_id=99999) assert result is None
